<span class="line"><span style="color:#F38BA8;font-style:italic;">        self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">failure_count </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 0</span></span>
